INSERT INTO question_event (question_id, event_id) SELECT q.id, e.id FROM question q JOIN event e ON e.event_key = q.duplicate_check_hash AND e.version = 'v1.0' WHERE q.duplicate_check_hash LIKE 'v3q-%' ON CONFLICT (question_id, event_id) DO NOTHING;
